#include <stdio.h>
#include <math.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int A, B, C;
        scanf("%d %d %d", &A, &B, &C);
        double x[N], y[N];
        for (int i = 0; i < N; i++) {
            scanf("%lf %lf", &x[i], &y[i]);
        }
        double minDist = 1e18;
        double minX, minY;
        for (double t = -5000; t <= 5000; t += 0.01) {
            double dist = 0;
            for (int i = 0; i < N; i++) {
                double d = fabs(A * x[i] + B * y[i] + C) / sqrt(A * A + B * B);
                dist += d;
            }
            if (dist < minDist) {
                minDist = dist;
                minX = t;
                minY = -C / (double)B;
            }
        }
        printf("%.6f\n", minDist);
    }
    return 0;
}

