import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int A = sc.nextInt();
            int B = sc.nextInt();
            int C = sc.nextInt();
            double[] x = new double[N];
            double[] y = new double[N];
            for (int i = 0; i < N; i++) {
                x[i] = sc.nextDouble();
                y[i] = sc.nextDouble();
            }
            double minDist = 1e18;
            double minX, minY;
            for (double t = -5000; t <= 5000; t += 0.01) {
                double dist = 0;
                for (int i = 0; i < N; i++) {
                    double d = Math.abs(A * x[i] + B * y[i] + C) / Math.sqrt(A * A + B * B);
                    dist += d;
                }
                if (dist < minDist) {
                    minDist = dist;
                    minX = t;
                    minY = -C / (double)B;
                }
            }
            System.out.printf("%.6f\n", minDist);
        }
    }
}

