const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const [A, B, C] = readline().split(' ').map(Number);
    const x = new Array(N);
    const y = new Array(N);
    for (let j = 0; j < N; j++) {
        [x[j], y[j]] = readline().split(' ').map(Number);
    }
    let minDist = 1e18;
    let minX, minY;
    for (let t = -5000; t <= 5000; t += 0.01) {
        let dist = 0;
        for (let j = 0; j < N; j++) {
            const d = Math.abs(A * x[j] + B * y[j] + C) / Math.sqrt(A ** 2 + B ** 2);
            dist += d;
        }
        if (dist < minDist) {
            minDist = dist;
            minX = t;
            minY = -C / B;
        }
    }
    console.log(minDist.toFixed(6));
}
